// processRefund.test.ts

import { processRefund } from "./processRefund";

describe("processRefund", () => {
  // AC1: Credit card refunds have no fee
  it("AC1: applies zero fee for credit_card refunds", () => {
    const result = processRefund("ORDER-001", 100, "credit_card");
    expect(result.fee).toBe(0);
    expect(result.refundAmount).toBe(100);
    expect(result.status).toBe("approved");
    expect(result.orderId).toBe("ORDER-001");
  });

  // AC2: Bank transfer refunds have a 1.50 fee deducted
  it("AC2: deducts 1.50 fee for bank_transfer refunds", () => {
    const result = processRefund("ORDER-002", 100, "bank_transfer");
    expect(result.fee).toBe(1.5);
    expect(result.refundAmount).toBe(98.5);
    expect(result.status).toBe("approved");
  });

  // AC3: Empty orderId throws validation error
  it("AC3: throws when orderId is an empty string", () => {
    expect(() => processRefund("", 100, "credit_card")).toThrow(
      "orderId is required"
    );
  });

  // AC4: Amount of 0 throws validation error
  it("AC4: throws when amount is 0", () => {
    expect(() => processRefund("ORDER-003", 0, "credit_card")).toThrow(
      "amount must be positive"
    );
  });

  // AC5: Amount of 10001 throws validation error
  it("AC5: throws when amount exceeds 10000", () => {
    expect(() => processRefund("ORDER-004", 10001, "credit_card")).toThrow(
      "amount exceeds maximum refund limit"
    );
  });

  // AC6: Amount of 10000 is valid (boundary — should succeed)
  it("AC6: accepts amount of exactly 10000 (upper boundary)", () => {
    const result = processRefund("ORDER-005", 10000, "credit_card");
    expect(result.refundAmount).toBe(10000);
    expect(result.status).toBe("approved");
  });

  // AC7: Whitespace-only orderId throws validation error
  it("AC7: throws when orderId is whitespace-only", () => {
    expect(() => processRefund("   ", 100, "credit_card")).toThrow(
      "orderId is required"
    );
  });
});
